(67, 'mail_auto', '手动模板', 2, '【Bibicopy】注文通知<br />\r\n{consignee} 様<br />\r\nお世話様です、<br />\r\n私は 中村 健一 管理者です、当店へお越し頂きありがとうございます。<br />\r\nこの度は、ご注文頂き、誠にありがとうございます。<br />\r\n下記の通りご注文を頂いておりますので、【ログイン】、ご確認ください。<br /><br />\r\n\r\n・【ご注文商品情報】<br />\r\n\r\n{product}\r\n<br />\r\n備考：{zipcode}<br /><br />\r\n\r\n◆お振込について<br />\r\n\r\n\r\n\r\n\r\n配送先情報<br />\r\n-------------------------------<br />\r\n{consignee}<br />\r\n{tel}<br />\r\n〒{zip}<br />\r\n{address}<br />\r\n{mobile}<br />\r\n-------------------------------<br /><br />\r\n\r\n振込み情報<br />\r\n****************************<br />\r\n振込み名義人（フリガナ）：(　 　 　 )<br />\r\n振込み金額：　 円<br />\r\n振込み日：　 月　 日　 時<br />\r\n\r\n****************************<br />\r\n\r\n入金後、会員マイページ、メッセージを残してお知らせください。<br />\r\n(IDはEメール / 初期パスワードは郵便番号、または、「パスワードをお忘れの方」をクリックして。）<br />\r\n<br />\r\n<span style=\"color:Red;\">ATMまたは 銀行振り込み後，[明細票の画像]をお送りください。<br />\r\nや インターネットバンキングで振込の明細 (スクリーンショット)</span>\r\n<br /><br />\r\n\r\n\r\nご連絡お待ちしております。<br />\r\n宜しくお願いいたします。<br /><br />\r\n\r\n\r\n※ 今後、メールが届かないことがありますので、必ず<b>ログイン</b>してご連絡ください。<br />\r\n※ 会員マイページのお知らせをご確認ください。 <br /><br />\r\n\r\n※ 日本語環境いにより、受信したメールが文字化けなる場合があります。<br />\r\n※ メールが届かない場合には、迷惑メールフォルダーを確認してみると届いているかもしれません。<br />\r\n<br />', 1),
(69, 'base_price', '基础价格', 2, '980', 1),
(77, 'usep', '使用积分比例', 3, '0.06', 1),
(78, 'onep', '单笔最高积分', 3, '3000', 1),
(71, 'mail_lot', '抽奖模板', 2, 'お客様、<br><br>\r\n\r\n私はBiBicopyの管理人です。当店へお越し頂きありがとうございます。<br><br>\r\n\r\nこのたびは「BiBicopyルーレット抽選会キャンペーン」に<br>\r\nご応募くださいまして誠にありがとうございました。<br><br>\r\n\r\n\r\n今回、当選おめでとうございます：<strong>{title}</strong>，（クーポンコード：<strong>{code}</strong>）<br>\r\nお知らせのメールをいたしました。<br><br>\r\n\r\nご注文・ご利用ください（クーポンコードを入力してください）<br><br>\r\n\r\n宜しくお願い致します。<br>\r\n\r\n\r\n', 1),
(73, 'points', '注册赠送积分', 3, '500', 1),
(74, 'opoints', '注文积分比例', 3, '0.01', 1),
(75, 'automail', '新客户未入款自动发订单', 4, '1', 1),
(88, 'site_prompt', '评论指令', 2, '请根据以下基础规则撰写评论：\r\n\r\n【商品名称】：{name}\r\n\r\n评论要求：\r\n\r\n- 该商品名称仅写1条评论\r\n\r\n- 评论语言：日语（可以偶尔带1~2个英文单词，但不能出现中文）\r\n\r\n- 不出现差评\r\n\r\n- 字数控制在10～50字符之间\r\n\r\n- 评论风格：口语化的语句（不要全部正式语）\r\n\r\n- 禁止出现“商品的名称”、“人物名字”、“コピー”、“偽物”、“N級品”等字样。\r\n\r\n- 禁止出现：unicode编码。\r\n\r\n- 禁止添加任何注释、解释语。\r\n\r\n- 偶发性出现（低于2%的概率）：“期待以上”或“想像以上”或“質感”\r\n\r\n- 整体风格方向：像「BUYMA・メルカリ」真实用户留言\r\n\r\n- 真实感规则：不要全部五星吹爆，5%的概率加入：小缺点/犹豫感/对比感/日常感\r\n\r\n- 省略主语\r\n\r\n- 不要夸张或诗化\r\n\r\n- 禁止事项：（避免像AI）不要“这是AI生成的”等提示语 ， 不要每句都完整 ，不要大量感叹号 ， 不要广告感用词', 1),
(92, 'member_comment', '评论方式', 3, '1', 1),
