INSERT INTO `div_page` (`id`, `title`, `thumb`, `keywords`, `description`, `content`, `template`, `listorder`) VALUES
(9, '网页底部导航', '', '', '', '', '', 0),
(22, 'ご注文方法', '', '注文方法', '', '商品をご注文時は下記のステップに基づき、行って下さい。わかりやすくて簡単！<br />\r\n<br />\r\n(1)、当店のホームでご注文したい商品をクリックしてください。<br />\r\n<br />\r\n(2)、買物かごをクリックして下さい。<br />\r\n<br />\r\n(3)、購入しますをクリックして下さい。<br />\r\n<br />\r\n(4)、各空欄にお客様の情報をご入力頂き、決定をクリックして下さい or 会員登録。<br />\r\n<br />\r\n(5)、注文内訳が「お客様センター」に送信されます<br />\r\n<br />\r\n(6)、ご注文後、お振込み下さい。当店により入金確認されましたら早速ご注文頂いた商品をご発送させて頂きます。<br />\r\n<br />\r\n(7)、追跡番号をお客様のメールアドレスに送信します、また「お客様センター」でも商品の発送を確認することができます。<br />\r\n<br />\r\n<br />\r\n「ＨＰ未掲載品でも他店の商品の詳細ページＵＲＬを送っていただければ在庫を確認しご連絡いたします。」<br />\r\n<br />\r\n最後までご覧いただき、誠にありがとうございます。<br />\r\n気持ちの良いお取引ができる様、尽力させていただきます。<br />\r\n【<a href=\"/replys.html\"><u><strong>Bibicopy 口コミ・評判No.1</strong></u></a>】,安心してお買い物をお楽しみくださいませ☆<br />\r\n安心の追跡つきでの発送でお届けします。<br />\r\n☆質問などございましたら、お気軽にお寄せ下さい！<br />\r\n<br />\r\n注意：<br />\r\n※ 迷惑メールの問題により、メールの送信を停止しています。<br />\r\n※ 今後、メールが届かないことがありますので、必ずログインしてご連絡ください。<br />\r\n<div style=\"display:block;text-align:center;margin:10px 0;height:30px;line-height:30px;border:2px solid #c99808;border-radius:10px;position:relative;\">\r\n	<a href=\"/News-64.html\" style=\"color:#c99808;\">【重要】偽Bibicopyサイト詐欺防止！！</a> \r\n</div>\r\n<br />\r\n<br />\r\n<p>\r\n	<a href=\"/replys.html\"><img style=\"max-width:99%;border-radius:10px;\" src=\"/Uploads/202412/674d59cbaec7b.jpg\" /></a> \r\n</p>', '', 0),
(49, '初めてのお客様', '', '', '初めてのお客様,ご利用規約', '<div style=\"font-size:12px;line-height:30px;margin-top:5px;text-indent:5px;\">\r\n	<p>\r\n		いらっしゃいませ！ようこそ【Bibicopy】！<br />\r\n当店はスーパーコピーブランド優良店。最新トレンドアイテムを厳選し、 感度の高いファッショニスタにも認められるクオリティを実現しています。\r\n	</p>\r\n	<div>\r\n		<img src=\"/Uploads/202203/6223151299944.jpg\" alt=\"生産工場の様子\" style=\"width:544px;\" /> \r\n	</div>\r\nコピー商品をお選びになる事情は皆様お持ちかと思いますが、国外でコピー品を購入する際は、細心の注意が必要です。 <br />\r\n*<strong>商品の品質はどうか</strong>？ <br />\r\n*<strong>ちゃんと届くのか</strong>？ <br />\r\n*<strong>外国のサイトだから不安</strong> <br />\r\n*<strong>個人情報を提供して大丈夫なのか</strong>？ <br />\r\n<br />\r\n	<p>\r\n		初めてご利用されるお客様にとっては大変不安なことと思います。ですが、ご安心下さい！<br />\r\n以下は初めてのお客様へのご利用案内も兼ねたご利用規約になります。<br />\r\nご利用の方は最後までお読みくださいますようお願いいたします。\r\n	</p>\r\n<br />\r\n	<h1 style=\"font-size:16px;line-height:40px;margin-top:5px;text-indent:5px;\">\r\n		ご利用規約\r\n	</h1>\r\n	<div>\r\n		<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n			１．商品の品質について\r\n		</div>\r\n		<p>\r\n			【Bibicopy】で取り扱う商品はN級、正規品と同じ原材料、 製造工程を踏んだ限りなく正規品に近い製品を取り扱っております。 一般の方では判別は難しいとされるレベルです。\r\n		</p>\r\n		<p>\r\n			◆生産工場と倉庫、国際便出荷拠点が分散されております。 ご注文を受けてから２回に渡る検品を経て、お客様のもとへ向けて出荷されます。\r\n		</p>\r\n		<p>\r\n			◆商品の写真。撮影時の天候、 カメラのホワイトバランスの設定やライティングの影響で実際の色味とは違って見える場合がございます。\r\n		</p>\r\n		<p>\r\n			◆サイト内画像は発売時のものを掲載しております。生産工場の変更や仕様のアップデートなどで掲載画像と差異がある場合がございます。\r\n		</p>\r\n	</div>\r\n	<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n		２．お支払方法につきまして\r\n	</div>\r\n	<p>\r\n		銀行振込による前払い\r\n	</p>\r\n	<p>\r\n		銀行振り込みによる前払いにてお支払いをいただく方法です。<br />\r\nご注文確定後、『会員センター』orご登録のメールにご注文確認メールが届きます。そちらに記載の銀行口座にご注文金額をお支払い下さい。<br />\r\nご入金確認後に商品の手配を行い、発送いたします。<br />\r\n迷惑メールの設定などにより、ご注文確認メールが届かないケースがございます。or『ログイン』<br />\r\nメールが届かない原因の多くはご利用のメールサービスの迷惑メールフィルタによるものです。<br />\r\n迷惑メールフォルダをご確認いただき、受信設定をお願いいたします。\r\n	</p>\r\n	<div>\r\n		<span style=\"color:#E53333;\"><strong>※当店からのメールが迷惑メールフォルダに振り分けられる可能性がございます。 受信ができない場合はメールの受信設定をご確認下さい。</strong></span> \r\n	</div>\r\n	<div style=\"font-size:15px;line-height:30px;margin-top:5px;text-indent:5px;\">\r\n		<a href=\"/mailsetting.html\" se_prerender_url=\"complete\"><span style=\"background-color:#337ab7;color:#FFFFFF;\"><strong>メールの受信設定方法＞＞</strong></span></a> \r\n	</div>\r\n	<div>\r\n		<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n			３．商品の配送について\r\n		</div>\r\n		<p>\r\n			当店では<strong><span style=\"color:#E53333;\">全品送料無料</span></strong>となっており、商品代金のみでご購入いただけます。<br />\r\n皆様がご利用いただきやすいよう、業界でも当店のみの取り組みとなっております。<br />\r\n発送は佐川急便 / EMS国際郵便にて行っております。<br />\r\n詳しくは<a href=\"/ems.html\" se_prerender_url=\"complete\">荷物の追跡について</a>。<br />\r\n<br />\r\n複数ご注文いただいた場合は、当店の判断でお荷物を複数個口に分けて発送する場合がございます。<br />\r\nその場合は、出荷毎にメールにて発送のお知らせをお送りさせていただきます。<br />\r\n輸入にあたり、通関などご不安があるかと存じます。当店ではお客様に安心してご利用していただけますようお荷物のお受け取りについても 万全のサポート体制をご用意しております。<br />\r\n<span style=\"color:#E53333;\">※第三国を経由してお送りしていた有料便の取扱いは廃止となりました。</span> \r\n		</p>\r\n	</div>\r\n	<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n		４．商品のお届け日数について\r\n	</div>\r\n	<p>\r\n		商品のお届けには多くの日数を要しますことをご理解下さい。 通常、ご注文をいただいてから商品を出荷するまでに4日～8日間程度のお日にちを頂戴しております。 これは弊社提携の工場に発注後、検品作業も行うための期間になります。<br />\r\nそこから空輸（３日～一週間程度）→通関（2日程度）→国内配送（２、３日程度）→お届け<br />\r\n概ね、上記のような流れになります。 通常は２週間～３週間以内のお届けとなりますが、 いずれかのフェーズで遅延が発生した場合はこの限りではありません。<br />\r\n出荷後は配送業者サイトからお荷物の追跡が可能です。 発送完了メールにてお荷物番号をお知らせいたしますので、出荷後の状況はご自身でご確認ください。<br />\r\n出荷後、一週間以上お荷物の追跡ができない場合はカスタマーサポートまでご連絡下さい。<br />\r\nいつ届くかというご質問に対して明確にお答えすることは困難です。 輸送日数は国際物流の情勢に大きく依存します。\r\n	</p>\r\n	<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n		５．税関検査について\r\n	</div>\r\n	<p>\r\n		国外からお荷物を輸入する場合、着荷空港にて税関検査が行われます。 税関検査では薬物などの危険物をはじめ、レプリカ製品も規制対象になります。<br />\r\n税関検査で商品の輸入が差し止められた場合は、お客様のもとへ通知が送られて参ります。<br />\r\n万が一没収された場合は、当社への再配送を依頼することが可能です。 お客様の利益を最優先でお守りするための当店独自の取組みになります。\r\n	</p>\r\n	<p>\r\n		◆輸入を差し止められた場合の流れ\r\n	</p>\r\n税関より通知がお客様のもとへ届きます。 <br />\r\n通知をスキャンいただくか写真を撮ってください。 <br />\r\n<br />\r\n	<p>\r\n		<span style=\"color:#E53333;\">※通知が届きましたら速やかに当店サポートまでご連絡いただけますようお願いいたします。</span> \r\n	</p>\r\n	<p>\r\n		◆再配送についてのご注意\r\n	</p>\r\n再発送をご希望された際、もし、同じ住所にお送りした場合は再び没収される可能性が高くなります。 できる限り、別の配送先をご指定いただけますようお願いいたします。 <br />\r\n<br />\r\n	<p>\r\n		◆商品の性質上、輸入差止のリスクをご了承いただいた上でのお取引となります。 通関サポート、再配送等の補償をご用意しておりますのでそちらをご利用ください。\r\n	</p>\r\n	<p>\r\n		税関に輸入を差し止めされ、通知が届くととても不安な気持ちになるかと思いますがご安心下さい。 お客様にとって不利益になることは一切ございません。最後まで当店が責任を持ってサポートさせていただきます。<br />\r\nご不安がございます場合はお気軽にご相談下さい。\r\n	</p>\r\n	<div>\r\n		<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n			６．ご注文のキャンセルについて\r\n		</div>\r\n		<p>\r\n			ご注文のキャンセルは、注文日より３日以内にご連絡下さい。 ご注文後、在庫切れなどの理由から当店より２週間以上発送のご連絡がない場合はキャンセル可能です。<br />\r\nキャンセルによる返金方法はお客様の銀行口座へお振込みとなります。<br />\r\n返金処理は当社規定の日時に限らせていただきます。\r\n		</p>\r\n	</div>\r\n	<div>\r\n		<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n			７．返品・交換について\r\n		</div>\r\n		<p>\r\n			商品を受け取ってから48時間以内にカスタマーサポートへご連絡下さい。 ご連絡の際は必ず不良部分の写真を添付いただきますようお願いいたします。<br />\r\n尚、お客様ご都合による返品・交換はお受けできませんので予めご了承下さい。<br />\r\n※イメージと違う、色味が違うなどお客様主観の一方的な理由での返品はお受けできかねます。\r\n		</p>\r\n詳しくは<a href=\"/fanping.html\">返品・交換</a>をご覧ください。\r\n	</div>\r\n	<div>\r\n		<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n			８．個人情報の取扱いについて\r\n		</div>\r\n		<p>\r\n			当店をご利用の際、ご注文時や会員登録時にお客様の個人情報をお預かりします。 お客様の個人情報を第三者に譲渡したり、漏洩などするこなく安全には十分に配慮し管理しています。<br />\r\n詳しくは<a href=\"/qingbao.html\">プライバシーポリシー</a>をご覧ください。\r\n		</p>\r\n	</div>\r\n	<div>\r\n		<div class=\"terms-heading-bold\" style=\"box-sizing:inherit;background:#000000;color:#FFFFFF;padding:5px 10px;margin:16px 0px;font-weight:bold;\">\r\n			９．ご利用資格について\r\n		</div>\r\n		<p>\r\n			当社の取り扱うレプリカという商品の性質上、様々なお問合せがございます。 中には当社に対して悪意を持って接してこられる利用者様もございます。<br />\r\n無用なトラブルを避けるためにも、当社としましても善良なお客様との差別化を図り、 悪質な利用者様には断固として当店のご利用をお断りさせていただきます。\r\n		</p>\r\n当社または当社スタッフ個人に対する脅迫、恐喝と取れる内容のメールを送る方 <br />\r\nA.<strong>暴言や反社会的な発言を行う方 </strong><br />\r\nB.<strong>一般常識の欠如、社会的成熟度が不完全と思われる方 </strong><br />\r\nC.<strong>正規品に強いこだわりがある方 </strong><br />\r\nD.<strong>コピー品の性質を理解せず、過剰に神経質にクレームをつけられる方</strong> <br />\r\nE.<strong>その他、ご利用にあたって当社が不適切と判断した方 </strong><br />\r\n		<p>\r\n			当店を必要と考えて下さるお客様のお陰で成り立っております。 様々なご意見があることは承知しておりますが、「欲しい」と思う皆様の要望を叶えるため 今後も可能な限り皆様にコピー品通販としてのサービスを提供して参りたいと考えております。\r\n		</p>\r\n	</div>\r\n</div>\r\n<a href=\"/replys.html\"><img style=\"max-width:99%;border-radius:10px;\" src=\"/Uploads/202412/674d59cbaec7b.jpg\" /></a>', '', 0),
(66, 'スーパーコピー 割引・セール', '', '', 'セール', '<p style=\"font-size:12px;\">\r\n	<a href=\"/special_goods.html?cid=321\" style=\"fmargin-right:5px;color:#b29061;border:1px solid #b29061;border-radius:50px;padding:2px 5px;\" target=\"_blank\">腕時計割引</a> <a href=\"/special_goods.html?cid=322\" style=\"fmargin-right:5px;color:#b29061;border:1px solid #b29061;border-radius:50px;padding:2px 5px;\" target=\"_blank\">バッグ値下げ</a> <a href=\"/special_goods.html?cid=324\" style=\"fmargin-right:5px;color:#b29061;border:1px solid #b29061;border-radius:50px;padding:2px 5px;\" target=\"_blank\">ジュエリー セール</a>  <a href=\"/special_goods.html?cid=421\" style=\"fmargin-right:5px;color:#b29061;border:1px solid #b29061;border-radius:50px;padding:2px 5px;\" target=\"_blank\">洋服 SALE</a> <br />\r\nBibicopy【毎日更新】割引・セール一覧！エレガントなデザインからモダンなスタイルまで、幅広いコレクションが特別価格で手に入ります。この機会にお気に入りの<a href=\"/\" target=\"_blank\">スーパーコピー ブランド</a>をお得にゲットしてください。\r\n</p>', '', 0),
(67, '特別オファー1600円', '', '', '特別オファー：追加1600円割引！', 'いつも当店をご利用いただき、ありがとうございます！感謝の気持ちを込めて、N級製品を購入いただく際に、追加で1600円の割引をご提供いたします。\r\n<div style=\"text-align:left;display:inline-block;border-radius:5px;background-color:#fff;width:98%;margin:16px auto;box-shadow:0 1px 6px -1px rgba(0, 0, 0, .4);position:relative;cursor:pointer;\">\r\n	<div style=\"background-color:#ff9cc4;border-radius:5px 5px 0 0;\">\r\n		<p style=\"font-size:13px;text-align:center;color:#fff;font-weight:700;padding:12px 24px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin:0;\" alt=\"\">\r\n			対象商品：SNS 初めて利用1600円クーポン\r\n		</p>\r\n	</div>\r\n	<div style=\"display:flex;\">\r\n		<div style=\"margin:14px 2%;\">\r\n			<img style=\"height:150px;object-fit:contain;padding-left:2px;\" src=\"/Uploads/202311/6556d9b460719.jpg\" /> \r\n		</div>\r\n		<div style=\"flex-basis:100%;margin:auto 4% auto 2%;\">\r\n			<div style=\"color:#e8254c;font-family:Roboto, sans-serif;font-weight:500;\">\r\n				<span style=\"font-size:20px;position:relative;bottom:2px;\">¥ 1600 OFF</span> \r\n			</div>\r\n			<div style=\"font-size:13px;padding:5px 0;letter-spacing:.5px;\">\r\n				最低利用金額： 制限なし <br />\r\n有効期限：まで\r\n			</div>\r\n			<div style=\"background-color:#f1f1f1;border-radius:30px;padding:6px;margin-bottom:8px;\">\r\n				<span class=\"mycoupon-special-card__code-label\">コード:</span> <span style=\"font-size:11px;font-weight:700;letter-spacing:.5px;\"><a href=\"javascript:void(0);\">FE9ap</a><textarea id=\"copy32\" style=\"position:fixed;top:-20000px;\">FE9ap</textarea> <input type=\"button\" style=\"border:none;background:none;\" onclick=\"copyContent(32)\" value=\"クリックしてコピー\" /> </span> \r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>\r\n<script>\r\n        function copyContent(id){\r\n          $(\"#copy\"+id).select();\r\n          document.execCommand(\"Copy\");\r\n          alert(\"コピーが成功し、すぐに決済に進みます\");\r\n          }\r\n</script>', '', 0),
(23, '[Bibicopy]会社概要', '/Public/Images/gaiyao.jpg', '[Bibicopy]会社概要', '[Bibicopy] 会社概要', '<p>\r\n	<img src=\"/Public/Images/20171200.jpg\" /> <br />\r\n<br />\r\n	<table cellspacing=\"0\" cellpadding=\"0\" bordercolor=\"#999999\" border=\"1\" style=\"width:100%;\" class=\"ke-zeroborder\">\r\n		<tbody>\r\n			<tr>\r\n				<td style=\"width:25%;\">\r\n					会社名\r\n				</td>\r\n				<td>\r\n					ビビコピー 株式会社  / BibiCopy Co.,Ltd.\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					代表\r\n				</td>\r\n				<td>\r\n					中村 健一\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					所在地\r\n				</td>\r\n				<td>\r\n					広州市飞蛾西路1357号\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					創業\r\n				</td>\r\n				<td>\r\n					2020年4月\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					資本金/売上\r\n				</td>\r\n				<td>\r\n					資本金 14,00,000円\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					会員数\r\n				</td>\r\n				<td>\r\n					300,000+\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					<b>お問い合わせ</b> \r\n				</td>\r\n				<td>\r\n					『ログイン後』,会員マイページのお知らせ\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					顧客サービス\r\n				</td>\r\n				<td>\r\n					<a href=\"mailto:info@ddcopy.com\"><u>info@ddcopy.com</u></a> （緊急連絡先）\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					営業時間\r\n				</td>\r\n				<td>\r\n					月曜日~土曜日（08:30 ~ 23:30）  定休日:日曜日<br />\r\n(注文受付：24时间)\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					主要取引銀行\r\n				</td>\r\n				<td>\r\n					三井住友・三菱UFJ銀行・ゆうちょ銀行\r\n				</td>\r\n			</tr>\r\n			<tr>\r\n				<td>\r\n					業務内容\r\n				</td>\r\n				<td>\r\n					スーパーコピーブランド時計、バッグ、財布、<a href=\"/NIKE/\" target=\"_blank\">ナイキ</a>、<a href=\"/moncler/\" target=\"_blank\">モンクレール</a>、<a href=\"/brand_dior/\" target=\"_blank\">ディオール</a>、<a href=\"/shaneru/\" target=\"_blank\">シャネル</a>等<br />\r\n				</td>\r\n			</tr>\r\n		</tbody>\r\n	</table>\r\n</p>\r\n<br />\r\n<p>\r\n	<a href=\"https://www.bibicopy.net/website_home.html\"><img style=\"max-width:99%;border-radius:10px;\" src=\"/Uploads/202206/629886db9c2e8.jpg\" /> </a> \r\n</p>\r\n<br />\r\n<strong>最高ランクの『スーパーコピー』「匠の精神」</strong><br />\r\n<video class=\"video\" controls=\"controls\" height=\"400px\" loop=\"loop\" poster=\"Uploads/202105/6096392dae2e7.jpg\" preload=\"none\" width=\"100%\"> <source src=\"/Uploads/202105/60962b65c6be3.mp4\" type=\"video/mp4\"> </video>\r\n<br />\r\n<p>\r\n	弊社スーパーコピーブランド販売ショップ！メンズ時計専門店をご覧頂き誠にありがとうございます。豊富な品数を備えているほか、スーパーコピーの最新入荷を追い求め、その最新作品のコピーブランド品を提供する一方、スーパーブランドコピー品の供給を保証することができます。超人気高級ウブロ・ロレックス・オメガ・等提供してあげます!ブランド時計専門店はお客様がご安心に購入いただけるように、最高ランクの『スーパーコピー』、N級品のみを扱っており、取扱い販売をさせていただいております。\r\n</p>\r\n<br />\r\n<p>\r\n	【<a href=\"/replys.html\"><u><strong>Bibicopy 口コミ・評判No.1</strong></u></a>】 「信用第一」「お客様第一」という信念を持ち、弊社は商品の値段を安く提供することに成功したため、皆様を楽しくお買い物いただけるよう、心を込めて最高なスーパーコピー品をご提供しております。 ご利用を心からお待ちしております。\r\n</p>\r\n<video class=\"video\" controls=\"controls\" height=\"400px\" loop=\"loop\" poster=\"/Uploads/202203/6223151299944.jpg\" preload=\"none\" width=\"100%\"> <source src=\"/Uploads/202203/622314d9d9da3.mp4\" type=\"video/mp4\"> </video>\r\n<p>\r\n	心の自信と平和を頼りに、創業以来、弊社は、健全な事業活動を推進していきました。弊社は現在、外国の貿易関係を運営していますが、主にスーパーコピー時計を販売しております。高い品質、良いサービス、競争力のある価格を要点として、お客様からの提案やニーズを重視致し、いつでも、どこでも、快適なオンラインショッピング体験をご提供します。\r\n</p>\r\n<p>\r\n	安心してお買い物をお楽しみくださいませ☆<br />\r\n<strong>>> <u><a href=\"/sagawas.html\">荷物の追跡番号 一覧</a></u></strong> (最新の出荷写真) <br />\r\n<br />\r\n気持ちの良いお取引ができる様、尽力させていただきます。<br />\r\n☆質問などございましたら、お気軽にお寄せ下さい！\r\n</p>\r\n<br />\r\n<div style=\"display:block;text-align:center;margin:10px 0;height:30px;line-height:30px;border:2px solid #c99808;border-radius:10px;position:relative;\">\r\n	<a href=\"/News-64.html\" style=\"color:#c99808;\">【重要】偽Bibicopyサイト詐欺防止！！</a> \r\n</div>\r\n<br />\r\n<p>\r\n	<a href=\"/replys.html\"><img style=\"max-width:99%;border-radius:10px;\" src=\"/Uploads/202412/674d59cbaec7b.jpg\" /></a> \r\n</p>', '', 0),
(41, '★★ご注文・お客様窓口★★', '', '', '※ 万一、当店のメールを届かないことがあれば，ご注文番号を入力してください。メッセージを残す事ができます。', '<div style=\"padding:5px;font-size:12px;\">\r\n	※メッセージを残す・注文内容・状況確認ができます。メッセージを残す、なるべく早く返信します。\r\n</div>\r\n<div style=\"padding:5px;font-size:12px;\">\r\n	※お問い合わせについて，お問い合わせの際に入力されたメールアドレスを以下に入力してください。\r\n</div>\r\n<div style=\"padding:5px;font-size:12px;text-align:center;\">\r\n	お問い合わせの前に、「<a href=\"/faqs.html?v=qas\"><u>よくあるご質問</u></a> 」をご利用ください。\r\n</div>', '', 0),
(30, '一番信用スーパーコピー ブランド口コミ Bibicopy', '', 'Bibicopy口コミ,一番信用スーパーコピー ブランド口コミ,お客様の声一覧，高評価，信頼できる!', '一番信用スーパーコピー ブランド口コミ,Bibicopy口コミ,お客様の声・レビュー 一覧,高評価，評判 信頼できる口コミサイト!お客様の率直な感想、ご満足頂いたお声などBibicopyのリアルな評判、評価をご覧ください。BiBicopy 買ってみた【購入者の口コミ】，送料無料、品質3年保証で。', '', '', 0),
(24, '荷物の追跡，スーパーコピー信用できるサイト', '/Public/Images/ems.jpg', '佐川急便 / EMS追跡', 'スーパーコピー信用できるサイト，佐川急便 / EMS追跡，\r\n', '<br />\r\n<strong> <a href=\"/sagawas.html?v=ems\"><span style=\"font-size:16px;\"> >><u> 荷物の配送  追跡番号  一覧</u></span> </a></strong> <br />\r\n<br />\r\n<br />\r\n<strong>1*佐川急便 お荷物問い合わせサービス</strong><br />\r\n<br />\r\n検索ＵＲＬ：https://k2k.sagawa-exp.co.jp/p/sagawa/web/okurijoinput.jsp<br />\r\n<p>\r\n	送り状（伝票）の控えにある、「お問い合せ送り状No.」欄の数字を「お荷物問い合わせサービス」に入力していただくと、現在のお荷物の輸送状況が瞬時に分かります。\r\n</p>\r\n<br />\r\n(<span style=\"color:#E56600;\">注意</span>：日本国内とは異なり、中国佐川急便の追跡は日本に入ってきてからじゃないと反映されません。<br />\r\n配送番号が発行・反映されるまでに4日～13日ほどかかる場合がございます。<br />\r\n通常、商品は4日間～14日間でお届け可能です。）<br />\r\n<br />\r\n<strong>2.*国際郵便 EMS追跡</strong><br />\r\n<p>\r\n	<img src=\"/Public/Images/zhuiji.jpg\" alt=\"\" /> \r\n</p>\r\n<p>\r\n	当日確認する、当日発送、 3～14日後、下記のＵＲＬて追跡できます↓ 7日~15日 に商品を受け取っていないで、頼むことは遠慮してはいけなくて、私達と連絡する\r\n</p>\r\n<p>\r\n	不明点、等があれば、ご遠慮なく言って下さい　　&nbsp;<br />\r\n商品は必ず貴地に届けるまでこっちのほうも追跡しますので、ご心配しなくでもいいです。\r\n</p>\r\n<p>\r\n	日本検索ＵＲＬ： http://www.int.post.japanpost.jp/&nbsp;<br />\r\n携帯検索ＵＲＬ： http://tracking.post.japanpost.jp/service/mobile_num_search.do?searchKind=S004\r\n</p>\r\n<br />\r\n<p>\r\n	<strong>*配送について</strong><br />\r\n【配送料】 &nbsp; &nbsp; 全国一律送料無料。<br />\r\n【配送会社】 &nbsp; &nbsp; EMS&nbsp;<br />\r\n【配送日】&nbsp; &nbsp; 6～14日間で到着できます。<br />\r\n【配送時間】 &nbsp; &nbsp; お届け時間ご指定できます。<br />\r\n（午前中　・12:00-14:00　・14:00-16:00　・16:00-18:00 ・18:00-20:00　・20:00-21:00）<br />\r\n*梱包には絶対に丈夫、安全、ご安心ください。\r\n</p>', '', 0),
(25, '個人情報について', '/Public/Images/qingbao.jpg', '個人情報', '個人情報保護', '<br />\r\n[Bibicopy]は、経営理念と自ら定めた行動規範に基づき、社会に貢献し、すべてのお客様からの信頼を得るとともに、当社への期待に応えるべく事業活動を進めていきます。個人情報は、厳正に管理すべきお客様の大切な財産であり、当社にとっても新たな価値創造の源泉となる重要資産です。<br />\r\n当社は、お客様の個人情報を以下の基本方針に従って取り扱います。<br />\r\n<br />\r\n<strong>プライバシーポリシー  基本方針</strong><br />\r\n<br />\r\n当社は、個人情報保護法および関連するその他の法令・規範を遵守します。また、当社は『Bibicopy 個人情報保護プログラム（以下、当社規程）』を着実に実施し、維持するとともに、継続的な改善に努めます。<br />\r\n<br />\r\n当社は、個人情報保護に関する管理体制を確立するとともに、当社規程を役員および従業員に周知し、その遵守徹底に努めます。<br />\r\n<br />\r\n当社は、個人情報をお客様に明示した利用目的の範囲内で取り扱います。また、当社はお客様からご提供いただいた個人情報を、お客様の同意がある場合または正当な理由がある場合を除き、第三者に開示または提供しません。<br />\r\n<br />\r\n当社は、個人情報を正確かつ最新の状態に保つとともに、個人情報への不正アクセス、個人情報の紛失、破壊、改ざんおよび漏えい等の予防に努めます。<br />\r\n<br />\r\n当社は、お客様からの個人情報に関するお問い合わせ、開示等のご請求に誠実かつ迅速に対応します。<br />\r\n個人情報の利用目的<br />\r\n&nbsp;<br />\r\n<strong>お客様に関する個人情報</strong><br />\r\n1） 商品の発送<br />\r\n2） 商品・サービス・催し物のご案内の送付<br />\r\n3） お問い合わせ・ご相談への対応<br />\r\n4） 保証書の発行、保証サービスの提供<br />\r\n5 ） 商品開発、アンケート調査実施、モニター実施<br />\r\n6 ） お客様との商談、打合せ等<br />\r\n<br />\r\n<strong>取引先各社、他社の役員・社員等に関する個人情報</strong><br />\r\n1） 業務上必要な諸連絡・商談等<br />\r\n2） 取引先情報管理、支払・収入処理<br />\r\n<br />\r\n<strong>採用応募者に関する個人情報</strong><br />\r\n1） 採用応募者（インターンシップを含む）への採用情報等の提供・連絡<br />\r\n2） 当社での採用業務管理<br />\r\n個人情報の提供<br />\r\n&nbsp;<br />\r\n当社は、次の場合を除き、お客様の個人情報を第三者に開示または提供しません。<br />\r\n1） お客様の同意がある場合<br />\r\n2） 法令に基づく場合<br />\r\n3） 人の生命、身体又は財産の保護のために必要であって、お客様の同意を取ることが困難な場合<br />\r\n4） 利用目的の達成に必要な範囲で、個人情報の取り扱いを委託する場合<br />\r\n5） 合併、会社分割、営業譲渡その他の事由によって事業の承継が行われる場合<br />\r\n<br />\r\n当社は、上記（1）にかかわらず、お客様からの商品や修理・サービスに関するお問い合わせ等に対し、当社の関係会社や代理店より対応させていただくことが適切と判断される場合に、お客様の住所、氏名、電話番号等を当該関係会社等へ提供することがあります。<br />\r\nこの場合、お客様は当社に対し当該関係会社等への個人情報提供の停止を請求することができます。<br />\r\n開示等の請求手続き<br />\r\n&nbsp;<br />\r\n当社は、保有するお客様ご自身の個人情報について<br />\r\n1) 開示の請求<br />\r\n2) 利用目的の通知の請求<br />\r\n3) 訂正の請求<br />\r\n4) 追加の請求<br />\r\n5) 消去の請求<br />\r\n6) 利用の停止または第三者提供の停止の請求　　に対応させていただいております。<br />\r\n<br />\r\n開示等の請求の申出先<br />\r\n開示等のご請求については、所定の請求書に必要書類を添付の上、郵送によりお願いいたします。請求書を当社へ郵送する際には、配達記録郵便や簡易書留郵便など、配達の記録が確認できる方法にてお願いいたします。<br />\r\nなお、封筒に朱書きで「個人情報請求書在中」とお書き添えいただければ幸いです。<br />\r\n&nbsp;<br />\r\nその他の事項<br />\r\n&nbsp;<br />\r\n本『個人情報保護方針』は、株式会社家悅の日本国内における個人情報の取り扱いに関するものです。当社の国内関係会社、および海外現地法人は対象としていません。<br />\r\n<br />\r\n当社がご提供する一部のサービス（当社が運営するウェブサイトのサービスを含む）では、お客様から個人情報をご提供いただけない場合はご利用できないものがありますので、あらかじめご了承ください。<br />\r\n<br />\r\n16歳未満のお客様は、保護者の方の同意を得た上で、個人情報をご提供いただきますようお願いします。<br />\r\n<br />\r\n当社では、より良くお客様の個人情報の保護を図るために、または、関係法令の変更に伴い、個人情報保護方針を改定することがあります。&nbsp;<br />\r\n<br />\r\nフリーメールをお使いのお客様から、「注文、問合せをしたけどメールが届かない」というご連絡を頂く場合がございます。フリーメールとは、無料で提供されるeメールサービスで、Hotmail・Yahoo！メール・gooフリーメール等があります。多くは、お客様がお使いのフリーメールの設定が原因で受信できないというのがほとんどです。万が一、「注文・落札又は問い合わせしてるけど半時間たっても当社からメールの返信がこない」という場合は、当社のその他のメールボックスは連絡します、またお使いのパソコンの以下の設定をご確認下さい。・受信メールボックスの容量　・受信拒否（迷惑メール機能）　・他メールへの転送設定!<br />\r\n（制定：平成24年 4月12日）<br />\r\n（改訂：平成24年 5月21日）<br />\r\n代表取締役社長 中村 健一<br />', '', 0),
(26, '返品について', '/Public/Images/fanpin.jpg', '返品について', '返品交換', '<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" width=\"100%\" style=\"color:#404040;font-size:12px;line-height:18px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td bgcolor=\"#000000\">\r\n				<span style=\"font-size:14px;\"><strong><span style=\"color:#FFFFFF;\"> もし、届いた商品に破損・キズのある場合、どうぞ下記の説明･流れをご参考ください。<br />\r\nご注文商品到着日より、1週間以上経過した場合、交換はお受けできません。</span></strong></span> \r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<br />\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" width=\"100%\" style=\"color:#404040;font-size:12px;line-height:18px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<img src=\"/Public/Images/0(6).jpg\" /> \r\n				<div>\r\n					製造するとき・運送中に発生したキズは可能です。バッグ上のキズ・汚れ・破損が2センチ以内はご容赦ください。\r\n				</div>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<p>\r\n					<img alt=\"\" src=\"/Public/Images/0(7).jpg\" /> \r\n				</p>\r\n				<div>\r\n					製造されたばかりの靴に皮のにおいがするかもしれませんが、時間と共に消えていきますので、どうぞご安心ください。また、照明の関係で若干の色差はご理解ください。\r\n				</div>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<p>\r\n					<img alt=\"\" src=\"/Public/Images/0(8).jpg\" /> \r\n				</p>\r\n				<p>\r\n					下記に該当する場合、どうぞ弊社までご連絡のほどよろしくお願いいたします。 <br />\r\n1.腕時計が到着してから一週間以内、一日での誤差は±30秒以上。<br />\r\n2.クロノグラフ，秒針は稼動しません。<br />\r\n3.部品・文字盤の数字が外れた場合、有料修理を提供いたします。\r\n				</p>\r\n				<p>\r\n					下記に該当する場合、どうぞ弊社までご連絡のほどよろしくお願いいたします。<br />\r\n汗や普通の雨、手洗いのときにぬれる程度までは耐えられますが、入浴や豪雨の時は危険です。これは『日常生活防水』といいます。\r\n				</p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>\r\n				<span style=\"color:#E53333;\">注意</span>：イメージと違う・サイズが合わない・注文内容の間違い・PC環境による色味の違いなどお客様都合による返品・交換は一切お受けいたしておりません。正規品と1：1の比例で製造しましたが、誤差がありますので、本物と若干の違いはご容赦ください。\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<br />\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" width=\"100%\" style=\"color:#404040;font-size:12px;line-height:18px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td bgcolor=\"#000000\">\r\n				<span style=\"color:#FFFFFF;\"><strong>返品・交換について</strong></span> \r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<br />\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" width=\"100%\" style=\"color:#404040;font-size:12px;line-height:18px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td>\r\n				<p>\r\n					(1）送料につきましては、お客様の負担となります。<br />\r\n(2）弊社の手違い・配送ミス以外の交換は、基本的にお断りしております。\r\n				</p>\r\n				<p>\r\n					交換をご希望の場合は、商品お届け後3日以内にカスタマーサポートまでご連絡をお願いいたします。交換の際の送料 はお客様負担となります。元と同じ状態の箱と包装紙が必要になります。 尚、交換は在庫がある場合に限り対応させていただきます。\r\n				</p>\r\n<br />\r\n				<p>\r\n					<strong>以下に該当する場合、商品が届いた三日以内、どうぞ弊社までご連絡のほどよろしくお願いいたします。</strong><br />\r\n• 異なる商品（色・モデルなど）が届いた場合<br />\r\n• サイズの誤差は3センチ以上/腕時計の誤差は0.5センチ以上<br />\r\n• 申込み数量と異なる数量が届いた場合<br />\r\n• 届けられた商品に汚れ・キズ（1センチ以上）・破損・<br />\r\nショルダーベルト/ハンドルの断裂等がある場合\r\n				</p>\r\n<br />\r\n				<p>\r\n					<strong>また、下記に該当する場合の交換はお受けできません。</strong><br />\r\n• ご使用後の商品・お客様のもとでキズや破損が生じた商品。<br />\r\n• 商品タグ、値札、ラベルなどが切り離された商品<br />\r\n• ご注文商品到着日より、1週間以上経過した商品。<br />\r\n• お客様のご希望での、特注商品や加工した商品。<br />\r\n• 特価品<br />\r\n• 交換商品が弊社に到着し商品の状態をチェックして、弊社の判断で傷みなど問題がある場合\r\n				</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<br />\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" width=\"100%\" style=\"color:#404040;font-size:12px;line-height:18px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td bgcolor=\"#000000\">\r\n				<span style=\"color:#FFFFFF;\"><strong>返品の流れ</strong></span> \r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<br />\r\n<p>\r\n	(1）お届けした商品が、ご注文と異なる商品/瑕・破損がある場合、3日以内に弊社までご連絡ください。<br />\r\n(2）間違い商品の写真を撮って、正確な注文した商品の番号と名前を教えてください。瑕・破損がある時、その部分は写真を撮ってメールで送信してください。原則的に不良品に限ります。<br />\r\n(3）返品するとき、いくつの注意点があるため、発送する前に、こちらに連絡してください。連絡しなかったら発送すれば、こちらは商品の問題を受理しなくて、それに責任も負わないことです。<br />\r\n(4）ご注文と異なる商品の場合、商品は傷がないことを確認してください、同時にパッケージは確実に商品を保護することを確認してください。商品を発送する時、こちらの指定した運送会社と送り先によって、規定時間以内に間違い商品を発送してください。あなたの商品を届いたら、述べた情況と一致することが確認してから、正確な商品を再発送しています。<br />\r\n(5）再発送のメールを届いたら、商品を査収することを注意してくださいませ。\r\n</p>\r\n<br />\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" width=\"100%\" style=\"color:#404040;font-size:12px;line-height:18px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td bgcolor=\"#000000\">\r\n				<span style=\"color:#FFFFFF;\"><strong>保証期間以内故障した場合</strong></span> \r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<br />\r\n<p>\r\n	(1）故障した商品の詳しい状況・写真を弊社までご連絡ください。<br />\r\n(2）使用上の誤りによる問題の場合、無駄の返送を避けるため、どうぞ弊社の指示・方法でお試し、また、先に地元で商品の修理をお受けください。<br />\r\n(3）商品を返送する前に、修理料金の必要かどうかについて、どうぞ弊社のオンラインチャットサポート・顧客センターまでご連絡ください。<br />\r\n(4）商品を発送したら、どうぞ追跡番号をご提供のほどよろしくお願いいたします。&nbsp;<br />\r\n(5）商品を届いたら、早速商品を検査させていただきます。述べた情況と一致することが確認してから、修理の手続きに入ります。<br />\r\n(6）修理・再発送完了後、追跡番号を送信いたします。\r\n</p>\r\n<br />\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" width=\"100%\" style=\"color:#404040;font-size:12px;line-height:18px;\">\r\n	<tbody>\r\n		<tr>\r\n			<td bgcolor=\"#000000\">\r\n				<span style=\"color:#FFFFFF;\"><strong>注文数量より少ない数量が届いた場合</strong></span> \r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n<br />\r\n<p>\r\n	(1）三日以内、商品の写真・パッケージをご提供ください。<br />\r\n(2）注文内容が確認でき次第、発送状況をお知らせします<br />\r\n(3）再発送しましたら、追跡番号を送信いたします。\r\n</p>\r\n<br />', '', 0),
(27, 'N級品(スーパーコピー)とは？', '', 'N級品,品質について,スーパーコピー N級品 品質', 'N級品とは,スーパーコピー n級品は最高品質のコピー商品、N級品はそれなりに原価が掛かっていて、本物とそん色ないレベルのコピー品です。N級品 サイト『BiBicopy』。', '<style>\r\n:root{\r\n  --main:#111;\r\n  --sub:#666;\r\n  --line:#e5e5e5;\r\n  --bg:#fafafa;\r\n  --title:#f3f3f3;\r\n  --accent:#111;\r\n}\r\n.nk-wrap{\r\n  max-width:1100px;\r\n  margin:0 auto;\r\n  padding:12px;\r\n  color:var(--main);\r\n  line-height:1.9;\r\n  font-size:15px;\r\n  word-break:break-word;\r\n}\r\n.nk-box{\r\n  background:#fff;\r\n  border:1px solid var(--line);\r\n  border-radius:16px;\r\n  padding:18px;\r\n  margin-bottom:22px;\r\n  box-shadow:0 2px 10px rgba(0,0,0,.03);\r\n}\r\n.nk-title{\r\n  background:var(--title);\r\n  border-left:4px solid #111;\r\n  padding:12px 14px;\r\n  border-radius:10px;\r\n  font-size:18px;\r\n  font-weight:700;\r\n  margin-bottom:16px;\r\n  line-height:1.6;\r\n}\r\n.nk-title a{\r\n  color:#111;\r\n  text-decoration:none;\r\n}\r\n.nk-desc{\r\n  font-size:15px;\r\n  color:#333;\r\n}\r\n.nk-desc strong{\r\n  color:#000;\r\n}\r\n.nk-video{\r\n  margin:18px 0;\r\n}\r\n.nk-video video{\r\n  width:100%;\r\n  height:auto;\r\n  border-radius:14px;\r\n  background:#000;\r\n}\r\n.nk-table-wrap{\r\n  overflow-x:auto;\r\n  margin:18px 0;\r\n}\r\n.nk-table{\r\n  width:100%;\r\n  border-collapse:collapse;\r\n  min-width:560px;\r\n  background:#fff;\r\n}\r\n.nk-table td{\r\n  border:1px solid #dcdcdc;\r\n  padding:10px;\r\n  font-size:14px;\r\n  text-align:center;\r\n}\r\n.nk-table tr:first-child td{\r\n  background:#f7f7f7;\r\n  font-weight:700;\r\n}\r\n.nk-highlight{\r\n  background:#fafafa;\r\n  border:1px dashed #ccc;\r\n  border-radius:12px;\r\n  padding:14px;\r\n  margin-top:14px;\r\n}\r\n.nk-link{\r\n  color:#111;\r\n  font-weight:700;\r\n  text-decoration:underline;\r\n}\r\n.nk-tags{\r\n  display:flex;\r\n  flex-wrap:wrap;\r\n  gap:10px;\r\n  margin-top:25px;\r\n}\r\n.nk-tags span{\r\n  border:1px solid #ddd;\r\n  border-radius:50px;\r\n  padding:7px 14px;\r\n  font-size:13px;\r\n  background:#fafafa;\r\n}\r\n@media(max-width:768px){\r\n  .nk-wrap{\r\n    padding:10px;\r\n    font-size:14px;\r\n    line-height:1.85;\r\n  }\r\n  .nk-box{\r\n    padding:15px;\r\n    border-radius:14px;\r\n  }\r\n  .nk-title{\r\n    font-size:16px;\r\n    padding:10px 12px;\r\n  }\r\n  .nk-table td{\r\n    font-size:13px;\r\n    padding:8px;\r\n  }\r\n}\r\n</style>\r\n<div class=\"nk-wrap\">\r\n	<!-- INTRO -->\r\n	<div class=\"nk-box\">\r\n		<div class=\"nk-title\">\r\n			<strong>N級品とは</strong> \r\n		</div>\r\n		<div class=\"nk-desc\">\r\n			\"ブランドの偽造品の中でも、<strong>素材、縫製、ロゴの精度などが本物に最も近い</strong>最高品質のランクです。プロの鑑定士でも肉眼での判別が困難なほど精巧で、1:1のコピー品やスーパーコピーとも呼ばれ。\"\r\n		</div>\r\n<br />\r\n		<p>\r\n			『スーパーコピーN級品サイト <a class=\"nk-link\" href=\"/\">BiBicopy</a> 』，当店のN級品は本物と見分けることができません！\r\n		</p>\r\n	</div>\r\n<!-- VIDEO -->\r\n	<div class=\"nk-box\">\r\n		<div class=\"nk-title\">\r\n			<strong>N級品</strong>「匠の精神」動画\r\n		</div>\r\n		<div class=\"nk-video\">\r\n			<video class=\"video\" controls=\"\" loop=\"\" poster=\"/Uploads/202105/6096392dae2e7.jpg\" preload=\"none\">\r\n        <source src=\"/Uploads/202105/60962b65c6be3.mp4\" type=\"video/mp4\">\r\n      </video>\r\n		</div>\r\n		<div class=\"nk-video\">\r\n			<video class=\"video\" controls=\"\" loop=\"\" poster=\"/Uploads/202203/621f2ca5dd90b.png\" preload=\"none\">\r\n        <source src=\"/Uploads/202203/621f2d1f6132c.mp4\" type=\"video/mp4\">\r\n      </video>\r\n		</div>\r\n		<div class=\"nk-highlight\">\r\n			スーパーコピーブランド（<strong>N級品</strong>）：あなたの探し当てることができる最高は水準を模造して、最も正規品に接近します！<br />\r\n其の一、お客様の立場に立ち、誠心誠意をもってお客様に接すること。<br />\r\n其の二、迅速かつ確実に商品をお客様のお手元にお届けすること。<br />\r\n其の三、『本物と同じ』と言うシンプルな目標を持ち、品質を極めること。<br />\r\nぜひ一度当店の商品をお試しください。驚きと満足を保証致します。ご利用をお待ちしております。\r\n		</div>\r\n	</div>\r\n<!-- WHAT -->\r\n	<div class=\"nk-box\">\r\n		<div class=\"nk-title\">\r\n			<strong>N級品とは？スーパーコピー N級品</strong> \r\n		</div>\r\n		<p>\r\n			本物を真似た偽物模造品複製品です。 パチ物 （バチ物パチモノぱちもの）バッタ物（バッタモン）ブランドコピーとかの言い方もありますが、これらは一般的に粗悪品のレプリカ商品をさしているようです。 その中でも非常に優れた商品をスーパーコピールイヴィトンなと言います。 アジア圏内の中国大陸韓国台湾などの工場で作られる。中でも中国の広州で作られるレプリカは非常に優れたものです。\r\n		</p>\r\n		<p>\r\n			■当店が数年、スーパーコピーN級品の販売経験を持っております。 製造技術がかなり成熟したルイヴィトン、シャネル、エルメス、グッチ、ROLEX、OMEGA 、HUBLOT等のコピー品、時計、バッグ、財布、靴、小物、手帳、アクセサリー、ベルトなど種類が揃っています。 仕入、検品、梱包など全部一流のベテランがしております。 商品とともに、高品質と安心をお届けいたします！\r\n		</p>\r\n		<div class=\"nk-video\">\r\n			<video class=\"video\" controls=\"\" loop=\"\" poster=\"/Uploads/202203/621f2ca6e8d5c.jpg\" preload=\"none\">\r\n        <source src=\"/Uploads/202203/621f2d4666fb4.mp4\" type=\"video/mp4\">\r\n      </video>\r\n		</div>\r\n	</div>\r\n<!-- BAG -->\r\n	<div class=\"nk-box\">\r\n		<div class=\"nk-title\">\r\n			<strong>(スーパーコピー)N級品バッグ</strong> \r\n		</div>\r\n		<p>\r\n			バッグ、財布の主要な部分はルイヴィトン専用の皮革を輸入しています かばんおは高級な変色真皮、変色の防止ため酸化するの時間は長いです 使用している革は、変色防止加工を施していますので、現在の色を長期間楽しめます。\r\n		</p>\r\n		<p>\r\n			内部は材料と本物を使って材料の一致して（上等なほらを含みます、専用の布、綿フランネルなど）を使います カバンの内部は、オリジナル同様の素材を使用しております。 金属の部品の品質の等級は優良です 金属部品の品質もオリジナル同様です。\r\n		</p>\r\n		<p>\r\n			作業の流れは優良です。シリアルナンバーがあって、偽物防止の線、防塵する袋、英文は札をつるして、説明書、誕生カードはすべて付いてる。\r\n		</p>\r\n		<p>\r\n			注文されてから発送までの作業もスムーズに行っています。シリアルナンバー、偽造防止のライン、保護用の袋（オリジナル同様）、英文のタグ、説明書、誕生日カードも付いています。\r\n		</p>\r\n		<p>\r\n			贈り物をすることあるいは要求のわりに高い者が個人で使用することに適します。プレゼントするのには適さないかもしれませんが、個人で使用するには最適です。\r\n		</p>\r\n		<p>\r\n			現在すでにネットを通して日本に売って、米国、カナダ、ドイツ。現在、インターネットを使って日本、アメリカ、ドイツ、カナダから注文が入っています。\r\n		</p>\r\n		<p>\r\n			極度的な作業の流れと製作の水準、今中国の最高級の製作の品質誇り、普通の市場の上に現物が少ない、大量の生産ラインを高品質で実現し、他に類のない価格で生産している。\r\n		</p>\r\n	</div>\r\n<!-- HERMES TABLE -->\r\n	<div class=\"nk-box\">\r\n		<p>\r\n			模造品の等級は説明します：\r\n		</p>\r\n		<p>\r\n			バック、財布、靴、ベルトなどの皮革の製品\r\n		</p>\r\n		<div class=\"nk-table-wrap\">\r\n			<table class=\"nk-table\">\r\n				<tbody>\r\n					<tr>\r\n						<td>\r\n							ネット店の等級\r\n						</td>\r\n						<td>\r\n							中国の等級\r\n						</td>\r\n						<td>\r\n							材料を作ります\r\n						</td>\r\n						<td>\r\n							列位\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td>\r\n							N品\r\n						</td>\r\n						<td>\r\n							1対1\r\n						</td>\r\n						<td>\r\n							特級の天然皮革(頭階皮)\r\n						</td>\r\n						<td>\r\n							☆☆☆☆☆\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n		</div>\r\n		<p>\r\n			1対1(N級品)高級の天然の皮革製作を使って、材料、品質の統一。手製で作ります、生産量は少なくて、包装の優。原版と相違を比較するのはとても小さいです。\r\n		</p>\r\n	</div>\r\n<!-- ROLEX -->\r\n	<div class=\"nk-box\">\r\n		<div class=\"nk-title\">\r\n			<strong> スーパーコピー時計N級品 </strong> \r\n		</div>\r\n		<div class=\"nk-table-wrap\">\r\n			<table class=\"nk-table\">\r\n				<tbody>\r\n					<tr>\r\n						<td>\r\n							ネット店の等級\r\n						</td>\r\n						<td>\r\n							中国の等級\r\n						</td>\r\n						<td>\r\n							材料\r\n						</td>\r\n						<td>\r\n							ムーブメント\r\n						</td>\r\n						<td>\r\n							列位\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td>\r\n							N品\r\n						</td>\r\n						<td>\r\n							1対1\r\n						</td>\r\n						<td>\r\n							特級の鋼材\r\n						</td>\r\n						<td>\r\n							スイスのムーブメント(新型)\r\n						</td>\r\n						<td>\r\n							☆☆☆☆☆\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n		</div>\r\n		<p>\r\n			時計1対1（N品）： N級品時計：特級の鋼材、スイスのムーブメント（新型）\r\n		</p>\r\n		<p>\r\n			CHANEL時計素材：本当の陶磁、スイスのムーブメント（新型）\r\n		</p>\r\n		<p>\r\n			石英，自動巻,風防はサファイアクリスタル,刻印完璧,最高級ステンレス使用(SUS316L)、腕から外してもなかなか見分けつかなく、素材も高価なものを用いて、重量なども考慮され、プロでもなかなか見分けがつきません。\r\n		</p>\r\n		<p>\r\n			スイスのムーブメント番号：ETA2824-2、ETA2750、ETA2752、ETA2783、ETA2789。ETA2752、ETA2783、ETA2789。\r\n		</p>\r\n		<p>\r\n			中国産ムーブメントの機能は制限して、3針以上の腕時計の文字盤と原版は少し違いができます、原版と同じにスイスのムーブメントの腕時計を使います。\r\n		</p>\r\n	</div>\r\n<!-- RANKING -->\r\n	<div class=\"nk-box\">\r\n		<p>\r\n			先ほど『BiBicopy n級品』についてご紹介しましたが、スーパーコピーサイトの信用性と口コミに関しても、多くの人が関心を寄せています。\r\n		</p>\r\n		<p>\r\n			その為、 <a class=\"nk-link\" href=\"/News-2022super_copy_ranking.html\" target=\"_blank\"> スーパーコピー優良サイト ランキング 口コミ </a> を参考にして、安全性と信用性に関して、お客様の購買前の検証をお勧めします。\r\n		</p>\r\n		<div class=\"nk-tags\">\r\n			<span>#n級品 おすすめサイト</span> <span>#N級品とは</span> <span>#スーパーコピー N級</span> \r\n		</div>\r\n	</div>\r\n</div>', '', 0),
(34, '今日売れ筋', '', 'スーパーコピーブランド専門店,每日売れ筋！最近売れたアイテム 一覧！', 'スーパーコピーブランド専門店,每日売れ筋！最近売れたアイテム 一覧！', 'スーパーコピー優良サイト,每日売れ筋！最近売れたアイテム一覧！\r\n人気ブランド：腕時計は<a href=\"/rolex/\" target=\"_blank\">ロレックス コピー</a>です，バッグと財布は<a href=\"/brand_vuitton/\" target=\"_blank\">ルイヴィトン コピー</a>です。', '', 0),
(37, 'スーパーコピー ちゃんと 届いた。Bibicopy届かない?', '', 'Bibicopy届かない? スーパーコピー ちゃんと 届いた', 'スーパーコピー ちゃんと 届いた，Bibicopy届かない? 商品が届かない！NO,本当に届く、信用できるサイト、高級ブランド偽物を日本で激安販売してい。', '<br />\r\n<h2 style=\"text-align:center;\">\r\n	<strong>スーパーコピー ちゃんと 届いた，Bibicopyたちの約束です！</strong> \r\n</h2>\r\n<br />\r\n<strong>Bibicopy届かない?  必ず届きます、安心してください。</strong><a href=\"/replys.html\"><u>Bibicopyの正直レビュー</u></a>も良いですよ。 <br />\r\n<br />\r\nいつもご愛顧していただき、誠にありがとうございます。<br />\r\n<br />\r\n<strong>>> <u><a href=\"/sagawas.html\">荷物の追跡番号 一覧</a></u></strong><br />\r\n<br />\r\n※発送期限について<br />\r\n原則として、注文完了, なるべく早く発送します。<br />\r\n※発送通知とは<br />\r\n商品を発送したことをお知らせする通知です or 【会員センター】でも商品の発送を確認することができます。<br />\r\n※会員マイページ： 『ログイン』 or <a href=\"mailto:info@ddcopy.com\"><u>info@ddcopy.com</u></a> <br />\r\n※ メールが届かない場合、別のメールアドレスを変更して、もう一度当店のメールアドレスに連絡してください。 <br />\r\n<br />\r\n<strong>Bibicopy商品が届かない？</strong>NO！ 本当に届く！信用できるサイト、送料無料，高級ブランド偽物<strong>N級品</strong>を日本で激安販売してい。<br />\r\n<br />\r\n<p>\r\n	<img src=\"/Uploads/202004/5ea16aa661661.jpg\" /> \r\n</p>\r\n<br />\r\n※追跡サービスについて <br />\r\n■このホームページの「トラッキングNo」より配送状況を確認できます。4―14日到着することができます。<br />\r\n追跡できる配送方法の場合、荷物の紛失の可能性は極めて低いので、状況を確認しながらお待ちください。<br />\r\n<br />\r\n※場合により、WEB上に反映されるまでに時間がかかる事があります。<br />\r\n以下の原因などが考えられますので、出品者・購入者の双方で連絡をとり合いつつ、商品を探していただくようお願いいたします。<br />\r\n→投函先が間違っている可能性（運送会社にお問い合わせください）<br />\r\n<p>\r\n	<img src=\"/Uploads/202112/61cc28ed9b461.jpg\" /> \r\n</p>\r\n<br />\r\n※商品が配送中に破損してしまった<br />\r\n到着した時点で商品が破損している場合、検品時には確認できなかった破損に関しては、配送中に発生した可能性があります。<br />\r\n私達に連絡してください、賠償します。<br />\r\n<br />\r\n※ 万一注文して、当店の注文メールを届かないことがあれば、お手数ですが、別のメールアドレスを変更して、もう一度当店のメールアドレスに連絡してください。特に@docomo.ne.jpと@ezweb.ne.jpのお客様はご注意してください。<br />\r\n※ 商品を購入する際に、先にご確認希望の事項がございましたら、どうぞ【その他のお問い合わせ】にご記入ください。<br />\r\n※ お客様への返信は12時間内に行います。どうぞご安心ください。もし、時間内にメールが届かない場合、どうぞ着信拒否の設定をご確認いただくか、直接画面の左上の顧客センターまでお問い合わせください。どうぞよろしくお願いいたします。<br />\r\n<p>\r\n	<img src=\"/Uploads/202004/5ea16abe9bc74.jpg\" /> \r\n</p>\r\n<br />\r\nもし我々の商品に満足しているならば、半分時間を掛かって貰って良い評価を付いていただければ幸いです。ご評価を我々にとても大切です,これに対して,本店は1000円クーポン券を贈り致します!ご支援ありがとうございます.<br />\r\nご愛顧ありがとうございます，もっと多いの協力を期待致します。どうもありがとうございます!ご多幸をお祈り申し上げます。<br />\r\n<br />\r\n<div style=\"display:block;text-align:center;margin:10px 0;height:30px;line-height:30px;border:2px solid #c99808;border-radius:10px;position:relative;\">\r\n	<a href=\"/News-64.html\" style=\"color:#c99808;\">【重要】偽Bibicopyサイト詐欺防止！！</a> \r\n</div>\r\n<br />', '', 0),
(73, '実物動画 一覧', '', '', '人気のスーパーコピー品の実物動画をご紹介、より安心してご利用いただけます', '人気のスーパーコピー品の実物動画をご紹介、より安心してご利用いただけます！', '', 0),
(39, 'よくあるご質問（FAQ）', '', 'よくあるご質問（FAQ）Bibicopy,お客さまからよくいただくご質問にお答えします。', 'よくあるご質問（FAQ）スーパーコピー Bibicopy,お客さまからよくいただくご質問にお答えします。', '<br />\r\n<h2>\r\n	Bibicopy よくあるご質問\r\n</h2>\r\n<br />\r\nご購入前-ご購入後のサポートも毎日行わせて頂いておりますので、是非お気軽にご連絡くださいませ\r\n過去に頂きましたお問い合わせ等からBibicopyに関するご質問を掲載しております<br />\r\n<br />\r\n『Bibicopy』<a href=\"/\">スーパーコピー</a>専門店　<br />\r\n営業時間：平日09:00～19:30　(24時間注文受付中！！)<br />\r\n<br />\r\n<strong>Q． 入金方法は？</strong><br />\r\nご入金は銀行振り込みです。注文確定後，お客様センターの『注文通知』に振込口座を記載しています。恐れ入りますが、お振込みの際の手数料はお客様ご負担となります。<br />\r\n<br />\r\n<strong>Q． 商品到着はいつになりますか？</strong><br />\r\nご入金確認後、通常、4日～8日間は発送いたします。商品の在庫やお届け先地域によって到着までの日数が異なりますが、普通は8日～18日でお届け可能です。<br />\r\n(<span style=\"color:Red;\">※ 商品お急ぎの方はご遠慮頂きます、到着遅れですぐに”詐欺”だと騒ぎ立てる方の購入はご遠慮ください。</span>)<br />\r\n<br />\r\n<strong>Q． 領収書の発行は可能ですか？</strong><br />\r\nはい、可能で御座います。<br />\r\nご注文いただいた場合は領収書を同封いたします。<br />\r\n<br />\r\n<strong>Q．クレジットカードは使えますか？</strong><br />\r\n申し訳御座いませんが、すべて現金のみのお取扱いとなっております。<br />\r\n<br />\r\n<strong>Q．分割払いは可能ですか？</strong><br />\r\n当店は現金のみのお取扱いとなっておりますので、分割払いはできません。<br />\r\n<br />\r\n<strong>Q．スーパーコピー新品ですか？ 中古品ですか？</strong><br />\r\n弊社は販売している商品は、<a href=\"/celine/\" target=\"_blank\">セリーヌ</a>，<a href=\"/brand_tiffany/\" target=\"_blank\">ティファニー</a>，すべて新品の商品です。中古品は一切取り扱いいたしておりません。<br />\r\n<br />\r\n<strong>Q．掲載されていない商品を取り寄せることはできますか？</strong><br />\r\n掲載されていない商品のお取り寄せは行なっております,<br />\r\nお問い合わせフォームに「商品型番」とご記入の上ご連絡ください。<br />\r\n<br />\r\n<strong>Q． 商品は箱に入っていますか？</strong><br />\r\n相応のブランドの箱に入っておりますので、ご安心ください。<br />\r\n<br />\r\n<strong>Q．海外</strong><strong>配送の場合、税関で没収されることはありませんか？</strong><br />\r\n場合によっては、税関で没収されることもございます。万一没収された場合でも、本ショップが無料で再発送いたしますので、どうかご安心ください。尚、卸売りのお客様につきましては、弊社の利潤が少ないこともあり、再発送ができないこともあります。ご相談には誠意を持って対応いたします。<br />\r\n<br />\r\n<strong>Q．返品の取り扱いは？</strong><br />\r\n返品のお取り扱いや、返品方法に関しましては、こちらの特別ページをご覧下さい。 →　<a href=\"/fanping.html\" target=\"_blank\" style=\"white-space:normal;\"><u>返品のお取り扱いについて</u></a><br />\r\n<br />\r\n<strong>Q．</strong><strong>コピーブランド品を購入することは違法ではないのですか？</strong><br />\r\n個人が使用することが目的で購入することは犯罪ではありません。<br />\r\n<br />\r\n<strong>Q． 送料を教えてください?</strong><br />\r\n送料は弊社が負担いたします。<br />\r\n<br />\r\n<strong>Q． 店頭での販売はしていますか？</strong><br />\r\n弊社はインターネットでの販売業務となります。店頭での販売は行っておりません。会社へお越しいただきましても、お買い物はできません。<br />\r\n<br />\r\n<strong>Q． 電話やFAXで注文できますか？</strong><br />\r\nご注文は、当サイトの注文フォームにてご注文ください。お問合せにつきましてもお問合せフォームをご利用くださいますようお願い致します。<br />\r\n<br />\r\n<strong>Q． 商品は正規品ですか？</strong><br />\r\n弊社の取扱い商品は全て、外見は本物と区別し難いほどの「スーパーコピー N級品」です。<br />\r\n<br />\r\n<strong>Q． 商品発送後、発送終了の連絡をしてもらえるのでしょうか？</strong><br />\r\nはい、ご注文して頂きました商品を発送後、お客様センター，佐川急便/EMS追跡を確認することができます。また、登録して頂きましたメールアドレス宛でも商品の発送を確認することができます。<br />\r\n<br />\r\n<strong>Q．ここに記載されてない点をお聞きしたいのですが？</strong><br />\r\n『ログイン』にてお気軽にお問い合わせくださいませ。<br />\r\n<br />\r\n<a href=\"/replys.html\"><img style=\"max-width:99%;border-radius:10px;\" src=\"/Uploads/202412/674d59cbaec7b.jpg\" /></a>', '', 0),
(43, '商品検索，商品を探す', '', '商品検索，商品検索結果，スーパーコピー，偽物，N級品，通販', '', '', '', 0),
(50, 'メールが届かないお客様', '', '', '', 'ご注文確定後、当店よりご注文確定メールがお客様のメールアドレスに届きます。<br />\r\n通常なら1日以内には届きますが、何らかの原因でメールが届かないことがございます。<br />\r\n<br />\r\n単なるメールアドレスの入力間違いではない場合は<br />\r\n<br />\r\n<span style=\"color:#E53333;font-size:14px;\"><strong>ご利用のメールソフトの迷惑メール設定</strong></span><br />\r\n<br />\r\nが原因であることがほとんどです。<br />\r\n<br />\r\nこの場合、当店のメールアドレスからの受信を許可することで問題なく受信が可能になります。<br />\r\n以下に各種フリーメール、キャリアメール（携帯）の受信設定のご案内ページのリンクをご案内いたします。<br />\r\n<br />\r\n<p>\r\n	<span style=\"font-size:16px;\">迷惑メールに振り分けられる場合の対処方法</span> \r\n</p>\r\n<br />\r\n<p>\r\n	<input id=\"copyTarget\" type=\"text\" value=\"info@ddcopy.com\" /> (コピー)\r\n</p>\r\n<br />\r\n<strong><a href=\"https://support.google.com/mail/answer/6579?hl=ja\" target=\"_blank\">Gmailの場合</a></strong><br />\r\n<strong><a href=\"https://www.yahoo-help.jp/app/answers/detail/a_id/47921/p/622\" target=\"_blank\">Yahoo!メールの場合</a></strong><br />\r\n<strong><a href=\"https://support.office.com/ja-jp/article/%E3%83%96%E3%83%AD%E3%83%83%E3%82%AF%E3%81%BE%E3%81%9F%E3%81%AF%E8%A8%B1%E5%8F%AF-%E8%BF%B7%E6%83%91%E3%83%A1%E3%83%BC%E3%83%AB%E8%A8%AD%E5%AE%9A-48c9f6f7-2309-4f95-9a4d-de987e880e46#bkmk_safesenders\" target=\"_blank\">hotmail、msn、Outlookの場合</a></strong><br />\r\n<strong><a href=\"https://www.nttdocomo.co.jp/info/spam_mail/domain/\" target=\"_blank\">docomoメールの場合</a></strong><br />\r\n<strong><a href=\"https://www.au.com/support/service/mobile/trouble/mail/email/filter/detail/domain/\" target=\"_blank\">auメールの場合</a></strong><br />\r\n<strong><a href=\"https://www.softbank.jp/mobile/support/mail/antispam/mms/whiteblack/\" target=\"_blank\">softbankメールの場合</a></strong><br />\r\nフリーメールやキャリアメールに限らず、メールソフトには必ずドメインの指定受信設定機能が設けられています。<br />\r\n上記以外のメールをご利用の場合は提供元のヘルプ等をご参照の上、設定をお願いいたします。<br />\r\n<br />\r\n<br />', '', 0),
(51, 'サイトマップ', '', 'サイトマップ', 'サイトマップ', '', '', 0),
(53, 'Bibicopyのブックマーク【URL】', '', 'BiBicopyホーム画面に追加で1000ポイント!', 'ホーム画面に追加で1000ポイントもらえる！「BiBicopy」からお得なキャンペーンのご紹介。\r\nよく利用するさーびすやショップをホーム画面に追加できるようになりました。\r\n', '<style>\r\n        .alert-box { background: #e13127; color: #fcfcfc; padding: 10px; font-size: 14px; border-radius: 8px; margin: 10px 0; text-align: center; }\r\n        .alert-box strong { font-weight: bold; }\r\n        .info-box { background: #fff; padding: 10px; font-size: 14px; border-radius: 8px; box-shadow: 0 2px 5px rgba(0, 0, 0, 0.1); margin: 10px 0; text-align: center; }\r\n        .link-container { display: flex; justify-content: space-between; gap: 10px; margin: 10px 0; }\r\n        .link-box { flex: 1; height: 40px; line-height: 40px; text-align: center; border-radius: 20px; }\r\n        .link-box--red { border: 1px solid #009900; background: #009900; }\r\n        .link-box--yellow { border: 1px solid #ffba53; background: #ffba53; }\r\n        .link-box a { color: #fff; text-decoration: none; display: block; font-size: 14px; }\r\n        .link-box a strong { font-weight: bold; }\r\n        .link-box:hover { opacity: 0.9; }\r\n        .guide-section { margin: 20px 0; }\r\n        .guide-section h3 { font-size: 16px; font-weight: bold; margin: 10px 0; }\r\n        .guide-section p { font-size: 14px; margin: 5px 0; }\r\n        .guide-section img { max-width: 100%; height: auto; border-radius: 8px; margin: 10px 0; }\r\n    </style>\r\n<!-- 警告提示 -->\r\n<div class=\"alert-box\">\r\n	⚠️<strong> 特殊な商品（コピー品）を扱っているため、サイトが攻撃されることが多く、または、ブランドに対する苦情により、サイトを一時的に閉鎖することがあります。詐欺は一切ありません！このページをホーム画面に追加して、必ず保存してください！</strong> \r\n</div>\r\n<!-- 信息提示 -->\r\n<div class=\"info-box\">\r\n	これは <strong>Bibicopyの緊急連絡先ページ</strong> です。<br />\r\nBibicopyのブックマークURLを今すぐホーム画面に追加！いつでもワンタップでアクセス可能！<br />\r\n今すぐ追加で <strong>1,000ポイント</strong> プレゼント！\r\n</div>\r\n<br />\r\n<!-- 链接框 -->\r\n<div style=\"“font-size:\" 11px;”=\"\">追加後、以下のリンクからアクセスしてください：\r\n	</div>\r\n	<div class=\"link-container\">\r\n		<div class=\"link-box link-box--red\">\r\n			<a href=\"https://www.bibicopy.net/\"><strong>Bibicopy</strong>の公式ページ</a> \r\n		</div>\r\n		<div class=\"link-box link-box--yellow\">\r\n			<a href=\"https://www.bibicopy.net/user/index.html\">会員マイページ</a> \r\n		</div>\r\n	</div>\r\n<br />\r\n<strong>iPhoneでショートカットを追加する方法</strong> <br />\r\niPhoneで【BiBicopy】のショートカットをホームに追加するには、SafariでBiBicopyを立ち上げます。<br />\r\n<br />\r\n１．<br />\r\n<img src=\"/Uploads/202206/62988799f092d.jpg\" /> <br />\r\n２．<br />\r\n【BiBicopy】を開いたら、[共有ボタン]をタップし、その中に存在する[ホーム画面に追加]を選択します。<br />\r\n	<p>\r\n		<img src=\"/Uploads/202206/629887b927ea9.jpg\" /> \r\n	</p>\r\n<br />\r\n<br />\r\n3.<br />\r\nこれでiPhoneでもショートカットにネイティブアプリと同じようなアプリアイコンが追加されました。<br />\r\n	<p>\r\n		<img src=\"/Uploads/202206/629887c81acdb.jpg\" /> \r\n	</p>\r\n<br />\r\n<br />\r\n<br />\r\n<b>Androidでショートカットを追加</b>（Twitter Liteを使うのは例です） <br />\r\n<br />\r\nChromeを開いたら右上の縦の三点リーダをタップして、[ホーム画面に追加]をタップします。<br />\r\n	<p>\r\n		<img src=\"/Uploads/202206/629887f79a704.jpg\" /> \r\n	</p>\r\n	<p>\r\n		<img src=\"/Uploads/202206/629887f7d5c95.jpg\" /> \r\n	</p>\r\n<br />\r\nあとはショートカットの名前を決めて「追加」押すと、Androidのホーム画面にTwitter Liteのショートカットが表示されます。<br />', '', 0),
(54, 'ご会員の利用案内', '', '会員の利用案内', '会員の利用案内', '<div style=\"padding:8px;font-size:10px;color:#E56600;\">\r\n	【<u>特殊な商品（コピー品）を扱っているため、ホームページが攻撃されることが多く、極端な場合は開かなくなることもありますが、ご安心ください。早急に修正し、ご連絡いたします。</u>】\r\n</div>\r\n<p>\r\n	<span style=\"margin-bottom:1.2rem;padding:.4rem 1.2rem;border-left:4px solid #2e73c8;color:#2e73c8;font-size:1.2rem;\"> STEP1　お知らせ一覧</span> \r\n</p>\r\n<br />\r\n<p>\r\n	すべての受信メッセージと送信メッセージ（時間順）<br />\r\n<img src=\"/Uploads/image/20220608/20220608100602_14608.png\" alt=\"\" /><br />\r\n<br />\r\n<br />\r\n具体的なご質問は、該当する注文番号をクリックしてください。 <br />\r\n<img src=\"/Uploads/image/20220608/20220608101253_96409.png\" alt=\"\" /> \r\n</p>\r\n<br />\r\n<p>\r\n	<span style=\"margin-bottom:1.2rem;padding:.4rem 1.2rem;border-left:4px solid #2e73c8;color:#2e73c8;font-size:1.2rem;\"> STEP2　お問い合わせ</span> \r\n</p>\r\n<br />\r\n<img src=\"/Uploads/image/20220608/20220608102931_96943.png\" alt=\"\" /> <br />\r\n<img src=\"/Uploads/image/20220608/20220608103931_46336.png\" alt=\"\" /><br />\r\n<br />\r\n<p>\r\n	<span style=\"margin-bottom:1.2rem;padding:.4rem 1.2rem;border-left:4px solid #2e73c8;color:#2e73c8;font-size:1.2rem;\"> STEP3　注文状態</span> \r\n</p>\r\n<br />\r\n各注文には、対応するステータスがあります<br />\r\n<img src=\"/Uploads/image/20220608/20220608102107_51315.png\" alt=\"\" /><br />\r\n<br />\r\n<p>\r\n	<span style=\"margin-bottom:1.2rem;padding:.4rem 1.2rem;border-left:4px solid #2e73c8;color:#2e73c8;font-size:1.2rem;\"> STEP4　ポイント履歴</span> \r\n</p>\r\n<br />\r\nポイント付与、履歴<br />\r\n<img src=\"/Uploads/image/20220608/20220608101647_84842.png\" alt=\"\" /><br />\r\n<br />\r\n<p>\r\n	<span style=\"margin-bottom:1.2rem;padding:.4rem 1.2rem;border-left:4px solid #2e73c8;color:#2e73c8;font-size:1.2rem;\"> STEP5　他の機能</span> \r\n</p>\r\n<p>\r\n	他の機能については、適宜、参照ください。\r\n</p>\r\n<p>\r\n	<img src=\"/Uploads/image/20220608/20220608103557_96952.png\" /> \r\n</p>', '', 0),
(56, 'LINEの友達追加', '', '', 'LINEの友達追加', '<strong>【特殊な商品（コピー品）を扱っているため、ホームが攻撃されることが多く、または、ブランドに対する苦情により、サイトを一時的に閉鎖することがあります。ご安心ください、私たちは詐欺をしません。このQRコードは、緊急連絡先、<span style=\"color:#E53333;\">LINEの友達追加</span>！】</strong> \r\n<p>\r\n	<img src=\"/Uploads/202210/634a664d10d21.jpg\" /><br />\r\n<br />\r\n【または、クリック：<a href=\"https://line.me/ti/p/ZMgJgcu92z\">line.me/ti/p/ZMgJgcu92z</a>】\r\n</p>', '', 0);
INSERT INTO `div_page` (`id`, `title`, `thumb`, `keywords`, `description`, `content`, `template`, `listorder`) VALUES
(57, 'お友だち紹介キャンペーン', '/Uploads/202304/6448f6ee09641.jpg', '', 'お友だち紹介キャンペーン クーポン【Bibicopy】', '<br />\r\n<p>\r\n	➤<a style=\"margin-right:5px;border:1px solid #06c755;border-radius:50px;padding:2px 5px;line-height:30px;\" href=\"http://line.me/R/msg/text/?【Bibicopyへのご招待】 下記URLより会員登録すると、Bibicopyのお買い物で使える1,000円分のポイントをプレゼント！ ◆ポイントがもらえる会員登録はこちらから https://www.bibicopy.net/?code=Y9IUJ4a1jMQ\">LINEで紹介する</a> \r\n</p>\r\n<div style=\"display:none;\" id=\"linkText\">\r\n	https://www.bibicopy.net/?code=Y9IUJ4a1jMQ\r\n</div>\r\n➤<button style=\"margin-right:5px;border:1px solid #06c755;border-radius:50px;padding:2px 5px;line-height:30px;\" onclick=\"copyLink()\">URLをコピーして友達にクーポンを贈る</button> <br />\r\n<p>\r\n	<img src=\"/Uploads/202304/6448f4201fc76.jpg\" style=\"max-width:100%;\" /> \r\n</p>\r\n<br />\r\n<div style=\"text-align:center;\">\r\n	<strong>お友だち紹介</strong> \r\n</div>\r\n<strong> \r\n<div style=\"text-align:center;\">\r\n	<strong><span style=\"font-size:16px;\">ご利用の流れ</span></strong> \r\n</div>\r\n</strong>\r\n<p>\r\n	<span style=\"font-size:16px;\"><b><br />\r\n</b></span>STEP 01,専用のURLをお友だちへ送信\r\n</p>\r\n<p>\r\n	STEP 02,専用のURLから会員登録\r\n</p>\r\n<p>\r\n	STEP 03,友だち紹介特典プレゼント\r\n</p>\r\n<p>\r\n	<strong><span style=\"font-size:14px;\"></span></strong> \r\n</p>\r\n<br />\r\n<div style=\"text-align:center;\">\r\n	<strong>STEP 01</strong> \r\n</div>\r\n<strong> \r\n<div style=\"text-align:center;\">\r\n	<strong><span style=\"font-size:14px;\">専用のURLをお友だちへ送信</span></strong> \r\n</div>\r\n</strong> <br />\r\nこのページの下部にある「LINEで紹介する」または「メールで紹介する」ボタンから、お友だちを招待してください。<br />\r\nお友だちのLINEまたはメールアドレスに、専用のURLが届きます。 <br />\r\n<p>\r\n	<img src=\"/Uploads/202304/6448f54befa6e.png\" style=\"max-width:100%;\" /> \r\n</p>\r\n<br />\r\n<br />\r\n<div style=\"text-align:center;\">\r\n	<strong>STEP 02</strong> \r\n</div>\r\n<span style=\"font-size:14px;\"> \r\n<div style=\"text-align:center;\">\r\n	<strong>専用のURLから会員登録</strong> \r\n</div>\r\n</span> <br />\r\n専用のURLを押すと、以下のように「友だち紹介特典」が表示された画面が開きますので、会員登録を行ってください。<br />\r\n<br />\r\n※「友だち紹介特典」が表示されていない画面から会員登録をすると、ポイントとクーポンは付与されません。 <br />\r\n<p>\r\n	<img src=\"/Uploads/202304/6448f69f65fcd.jpg\" style=\"max-width:100%;\" /> \r\n</p>\r\n<br />\r\n<br />\r\n<div style=\"text-align:center;\">\r\n	<strong>STEP 03</strong> \r\n</div>\r\n<div style=\"text-align:center;\">\r\n	<strong><span style=\"font-size:14px;\">友だち紹介特典をプレゼント</span></strong> \r\n</div>\r\n<br />\r\nお友だちがBibicopyの会員登録を完了すると、紹介者（あなた）宛にメールでクーポンコードが届きます。<br />\r\n<br />\r\nお友だちには、Bibicopyで使えるポイント（1ポイント＝1円分）をプレゼントします。<br />\r\nポイントはマイページで確認できます。 <br />\r\n<p>\r\n	<img src=\"/Uploads/202304/6448f7811ddf3.jpg\" style=\"max-width:100%;\" /> \r\n</p>\r\n<br />\r\n<div style=\"text-align:center;\">\r\n	＼ あなたもお友だちも、どちらもうれしい ／\r\n</div>\r\n<strong> \r\n<div style=\"text-align:center;\">\r\n	<strong><span style=\"font-size:16px;\">お友だち紹介はこちらから</span></strong>\r\n</div>\r\n</strong> <br />\r\n<p>\r\n	➤ <a style=\"margin-right:5px;border:1px solid #06c755;border-radius:50px;padding:2px 5px;line-height:30px;\" href=\"http://line.me/R/msg/text/?【Bibicopyへのご招待】 下記URLより会員登録すると、Bibicopyのお買い物で使える1,000円分のポイントをプレゼント！ ◆ポイントがもらえる会員登録はこちらから https://www.bibicopy.net/?code=Y9IUJ4a1jMQ\">LINEで紹介する</a> \r\n</p>\r\n<br />\r\n<script type=\"text/javascript\">\r\n    function copyLink(){\r\n      //获取文字\r\n      const text = document.getElementById(\"linkText\").innerText;\r\n      //创建input标签\r\n      const input = document.createElement(\"input\");\r\n      input.setAttribute(\"value\", text);\r\n      document.body.appendChild(input);\r\n      input.select();\r\n      document.execCommand(\"copy\");\r\n      document.body.removeChild(input);\r\n    alert(\"コピーが成功し、すぐに決済に進みます\");\r\n    }\r\n  </script>\r\n<div style=\"display:none;\" id=\"linkText\">\r\n	https://www.bibicopy.net/?code=Y9IUJ4a1jMQ\r\n</div>\r\n➤ <button style=\"margin-right:5px;border:1px solid #06c755;border-radius:50px;padding:2px 5px;line-height:30px;\" onclick=\"copyLink()\">URLをコピーして友達にクーポンを贈る</button> <br />\r\n<br />', '', 0),
(58, '【Bibicopy】QRコード', '', '', '', 'LINEのID: Bibicopy', '', 0),
(59, 'メールマガジンの変更・解除', '', '', '', '<div style=\"text-align:center;\">\r\n	<strong style=\"font-size:18px;\">配信停止要求が正常に受信されたこと</strong> \r\n</div>\r\n<div style=\"text-align:center;\">\r\n	<br />\r\n</div>\r\n<div style=\"text-align:center;\">\r\n	お客様がリクエストされた変更はまもなく有効となり、お客様には通知されなくなります。\r\n</div>\r\n<br />\r\n<br />\r\n<br />\r\n<br />\r\n<br />\r\n<br />\r\n<br />\r\n<br />\r\n<br />\r\n<br />', '', 0),
(61, 'スーパーコピーBibicopy クーポン', '', '', 'bibicopyスーパーコピー 割引クーポン✨最新✨増額中✨紹介キャンペーン友達紹介，SNS 限定 割引クーポン 友達 招待コード\r\n', '<strong>【Bibicopy】スーパーコピー 割引クーポン✨最新 SNS&nbsp;限定✨増額中✨紹介キャンペーン友達紹介 割引クーポン&nbsp;</strong><br />\r\n<div style=\"text-align:left;display:inline-block;border-radius:5px;background-color:#fff;width:98%;margin:16px auto;box-shadow:0 1px 6px -1px rgba(0, 0, 0, .4);position:relative;cursor:pointer;\">\r\n	<div style=\"background-color:#ff9cc4;border-radius:5px 5px 0 0;\">\r\n		<p style=\"font-size:13px;text-align:center;color:#fff;font-weight:700;padding:12px 24px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin:0;\" alt=\"初めて利用500円クーポン\">\r\n			対象商品：SNS 初めて利用777円クーポン\r\n		</p>\r\n	</div>\r\n	<div style=\"display:flex;\">\r\n		<div style=\"margin:14px 2%;\">\r\n			<img style=\"height:150px;object-fit:contain;padding-left:2px;\" src=\"/Uploads/202311/6556d9b460719.jpg\" /> \r\n		</div>\r\n		<div style=\"flex-basis:100%;margin:auto 4% auto 2%;\">\r\n			<div style=\"color:#e8254c;font-family:Roboto, sans-serif;font-weight:500;\">\r\n				<span style=\"font-size:20px;position:relative;bottom:2px;\">¥ 777 OFF</span> \r\n			</div>\r\n			<div style=\"font-size:13px;padding:5px 0;letter-spacing:.5px;\">\r\n				最低利用金額： 制限なし <br />\r\n有効期限：まで\r\n			</div>\r\n			<div style=\"background-color:#f1f1f1;border-radius:30px;padding:6px;margin-bottom:8px;\">\r\n				<span class=\"mycoupon-special-card__code-label\">コード:</span> <span style=\"font-size:11px;font-weight:700;letter-spacing:.5px;\"><a href=\"javascript:void(0);\">bnly5</a><textarea id=\"copy32\" style=\"position:fixed;top:-20000px;\">bnly5</textarea> <input type=\"button\" style=\"border:none;background:none;\" onclick=\"copyContent(32)\" value=\"クリックしてコピー\" /> </span> \r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>\r\n<br />\r\n<p style=\"font-size:12px;color:#000000;border-radius:8px;padding:10px 3px;border:1px solid #e9e9e9;\">\r\n	⭐随時更新するので、このページを<strong>ブックマーク</strong>していただければ、その時々に合ったキャンペーンを把握できます。\r\n</p>\r\n<p style=\"font-size:13px;color:#000000;border-radius:8px;padding:10px 3px;border:1px solid #e9e9e9;\">\r\n	<strong>「BiBicopy」はスーパーコピー優良サイト</strong>、ブランドコピーN級品おすすめ激安2024新作、信用届く、送料無料、品質保証！\r\n</p>\r\n<br />\r\n<script>\r\n        function copyContent(id){\r\n          $(\"#copy\"+id).select();\r\n          document.execCommand(\"Copy\");\r\n          alert(\"コピーが成功し、すぐに決済に進みます\");\r\n          }\r\n</script>\r\n<div style=\"border-bottom:10px solid #f3f3f3;\">\r\n	<div>\r\n		<ol style=\"padding:10px;\">\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_vuitton/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"ルイヴィトン\" src=\"/Uploads/202011/5fadefed4d56a.jpg\" /> \r\n				</div>\r\n				<div>\r\n					ルイヴィトン\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_rolex/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"ロレックス\" src=\"/Uploads/202108/6123533954f98.jpg\" /> \r\n				</div>\r\n				<div>\r\n					ロレックス\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_NIKE/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"ナイキ\" src=\"/Uploads/202108/611215bc0307a.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					ナイキ\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_dior/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"ディオール\" src=\"/Uploads/202105/609a23183b19a.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					ディオール\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_celine/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"セリーヌ\" src=\"/Uploads/202005/5ebe5c87da4eb.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					セリーヌ\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_chromeh/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"クロムハーツ\" src=\"/Uploads/201907/5d3a71a06e0f1.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					クロムハーツ\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_vancleef/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"ヴァンクリーフ\" src=\"/Uploads/202106/60b58eb244f6e.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					ヴァンクリーフ\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_hermes/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"エルメス\" src=\"/Uploads/202012/5fe18d0cd5ef5.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					エルメス\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_moncler/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"モンクレール\" src=\"/Uploads/202302/tyrg45s9jbc8u.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					モンクレール\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_gucci/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"グッチ偽物\" src=\"/Uploads/202203/6234452a32934.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					グッチ偽物\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_chanel/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"シャネル\" src=\"/Uploads/202005/5ec7a97983ab5.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					シャネル\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_supreme/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"シュプリーム\" src=\"/Uploads/201709/59ae476a6adba.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					シュプリーム\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_tiffany/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"ティファニー\" src=\"/Uploads/202012/5fdd9e036a338.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					ティファニー\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_loewe/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"ロエベ偽物\" src=\"/Uploads/202304/pv9qmpxtho607.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					ロエベ偽物\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_prada/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"プラダ偽物\" src=\"/Uploads/202304/642bbccc543e4.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					プラダ偽物\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_balenci/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"バレンシアガ\" src=\"/Uploads/201810/5bd404171f1a8.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					バレンシアガ\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_ap/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"オーデマピゲ\" src=\"/Uploads/201808/5b72af2a42ebb.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					オーデマピゲ\r\n				</div>\r\n</a> \r\n			</li>\r\n			<li style=\"display:inline-block;text-align:center;vertical-align:top;position:relative;margin:0;\">\r\n				<a href=\"/brand_omega/\"> \r\n				<div class=\"list_product_img_block pr\">\r\n					<img style=\"border-radius:50%;height:80px;\" alt=\"オメガ\" src=\"/Uploads/202107/60ee90627e81e.jpg\" /> \r\n				</div>\r\n				<div class=\"genre_name\">\r\n					オメガ\r\n				</div>\r\n</a> \r\n			</li>\r\n		</ol>\r\n	</div>\r\n</div>\r\n<br />\r\n<p>\r\n	<img src=\"/Uploads/202311/6555eb2428d80.jpg\" width=\"600\" alt=\"sale\" /> \r\n</p>\r\n<br />', '', 0),
