(1, 1, 1, 'gztokei', 'エア ジョーダン 1 レトロ HIGH OG &quot;Love Letter&quot;', '', '', '', '<span style=\"color:#111111;font-family:&quot;font-size:16px;text-wrap-mode:wrap;background-color:#FFFFFF;\">マイケル・ジョーダンがバスケットボール界から引退した際、この競技に捧げた最後のラブレターは、「Much Love and Respect（たくさんの愛と敬意を込めて）」という言葉で締めくくられていました。新しいエア ジョーダン&nbsp;1 HIGH OG \"Love Letter\"は、その献身的な想いを受け継いでいます。ヌバックレザーと柔らかいスエードのデザインで、伝統的なシルエットにアレンジ。これらの素材は、履き込むほどに味わい深い風合いを醸し出していきます。これは、彼のバスケットボールに対する献身、不屈の精神、情熱へのささやかなオマージュです。仕上げのディテールが、あの印象的な引退シーンを思い起こさせます。履き口とハングタグにあしらわれた「Much Love and Respect」の文字が、真の愛は時とともに深まることを思い出させてくれます。</span>', '0', '/Uploads/202607/6a47072d78039.jpg', 0, 1, '', 100, 102, 1783039644, 1783039644, '/pro-DZ5485_201.html', '/Uploads/202607/6a4708f15bc2e.jpg|AIR+JORDAN+1+LOW+G.jpglierenAIR+JORDAN+1+LOW+G.jpg:::/Uploads/202607/6a4708f16318b.jpg|AIR+JORDAN+1+MID.jpglierenAIR+JORDAN+1+MID.jpg:::/Uploads/202607/6a4708f16adea.jpg|AIR+JORDAN+1+RETRO+HIGH+OG.jpglierenAIR+JORDAN+1+RETRO+HIGH+OG.jpg', 0, '8', 0, 0, 0, 0, '', '26950', 0, '', '', '', '0', '', '', '', '该商品支持海外配送', 'DZ5485_201', 323, '', '495', '36950', '', '', '', '', 100, '0', 0, 0, ''),
(2, 1, 1, 'gztokei', 'ナイキ エア マックス 95 ビッグバブル &quot;OG&quot;', '', '', '', '<span style=\"color:#111111;font-family:\"font-size:16px;text-wrap-mode:wrap;background-color:#FFFFFF;\">エア マックス&nbsp;95は、人間の身体と90年代のトラック競技の美しいスタイルから着想を得たデザイン。抜群に快適な履き心地とスピード感のあるスタイルを兼ね備えています。波状のサイドパネルで、あらゆるコーディネートに自然な流れをプラス。ヒールと前足部に外から見えるクッショニングを配し、機能性が高く快適な履き心地を実現しています。</span>', '0', '/Uploads/202607/6a470b979300a.jpg', 0, 1, '', 100, 104, 1783040828, 1783042536, '/pro-HM4740_103.html', '/Uploads/202607/6a470ba63a56b.jpg|AIR+JORDAN+1+LOW+G.jpglierenAIR+JORDAN+1+LOW+G.jpg:::/Uploads/202607/6a470ba645cf4.jpg|AIR+JORDAN+1+MID.jpglierenAIR+JORDAN+1+MID.jpg:::/Uploads/202607/6a470ba64f1e6.jpg|AIR+JORDAN+1+RETRO+HIGH+OG.jpglierenAIR+JORDAN+1+RETRO+HIGH+OG.jpg:::/Uploads/202607/6a470ba656490.jpg|JORDAN+TRIANGLE+PF.jpglierenJORDAN+TRIANGLE+PF.jpg', 0, '8', 0, 0, 0, 0, '', '24200', 0, '', '', '', '0', '', '', '', '该商品支持海外配送', 'HM4740_103', 323, '', '495', '34200', '', '', '', '', 100, '0', 0, 0, ''),
(3, 1, 1, 'gztokei', 'ナイキ ReactX リジュビネイト', '', '', '', '<span style=\"color:#111111;font-family:\"font-size:16px;text-wrap-mode:wrap;background-color:#FFFFFF;\">柔らかく反発力の高いReactXフォームを使用したリジュビネイトで足に休息を。Nike最高レベルのテクノロジーを駆使した、履くのが待ち遠しくなるリカバリーシューズです。</span>', '0', '/Uploads/202607/6a470f3b8352a.jpg', 0, 1, '', 100, 162, 1783041846, 1783042524, '/pro-IR0291_200.html', '/Uploads/202607/6a470fcfd9a03.jpg|AIR+JORDAN+1+LOW+G.jpglierenAIR+JORDAN+1+LOW+G.jpg:::/Uploads/202607/6a470fcfe1742.jpg|AIR+JORDAN+1+MID.jpglierenAIR+JORDAN+1+MID.jpg:::/Uploads/202607/6a470fcfe8ee6.jpg|AIR+JORDAN+1+RETRO+HIGH+OG.jpglierenAIR+JORDAN+1+RETRO+HIGH+OG.jpg', 0, '8', 0, 0, 0, 0, '', '12540', 0, '', '', '', '0', '', '', '', '该商品支持海外配送', 'IR0291_200', 323, '', '495', '15540', '', '', '', '', 100, '0', 0, 0, ''),
(4, 1, 1, 'gztokei', 'ナイキ エア フォース 1 レトロ', '', '', '', '<span style=\"color:#111111;font-family:\" font-size:16px;text-wrap-mode:wrap;background-color:#ffffff;\"=\"\">快適で耐久性があり、時代を超えるスタイル。トップであり続けるのには理由があります。このエア フォース&nbsp;1は、クラシックなシルエットにデニムのテクスチャとパテント仕上げを組み合わせ、すっきりとしたクリーンなスタイルに仕上げました。</span>', '0', '/Uploads/202607/6a470fcfe1742.jpg', 0, 1, '', 100, 113, 1783042070, 1783042654, '/pro-IM5757_400.html', '/Uploads/202607/6a470fcfe8ee6.jpg|AIR+JORDAN+1+RETRO+HIGH+OG.jpglierenAIR+JORDAN+1+RETRO+HIGH+OG.jpg:::/Uploads/202607/6a470fcfe1742.jpg|AIR+JORDAN+1+MID.jpglierenAIR+JORDAN+1+MID.jpg:::/Uploads/202607/6a470fcfd9a03.jpg|AIR+JORDAN+1+LOW+G.jpglierenAIR+JORDAN+1+LOW+G.jpg:::/Uploads/202607/6a470f3b8352a.jpg|AIR+JORDAN+1+RETRO+HIGH+OG.jpglierenAIR+JORDAN+1+RETRO+HIGH+OG.jpg:::/Uploads/202607/6a470ebd1a86e.jpg|JORDAN+TRIANGLE+PF.jpglierenJORDAN+TRIANGLE+PF.jpg', 0, '8', 0, 0, 0, 0, '', '19800', 0, '', '', '', '0', '', '', '', '该商品支持海外配送', 'IM5757_400', 323, '', '495', '29800', '', '', '', '', 100, '0', 0, 0, '');
